import {BrandGithub} from "@vicons/tabler";
import {QqOutlined} from "@vicons/antd"

export default {
    components: {NDivider, NGradientText, NIcon},
    setup() {
        const state = reactive({
            circleUrl: 'img/img1.png',
            sizeList: ['small'] as const,
        })
        const {circleUrl, sizeList} = toRefs(state)
        return {
